import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                pkgs[pkg['id']] = (pkg['requestedVersion'], pkg['resolvedVersion'])
        result[name] = pkgs
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

print('=== Changes ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv != av:
            changes = True
            print(f'  {proj}: {pkg} {bv} -> {av}')
if not changes:
    print('  (none)')

print()
print('=== Unchanged ===')
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg)
        av = ap.get(pkg)
        if bv == av:
            print(f'  {proj}: {pkg} {av[0]} -> {av[1]}')
"

